<script setup lang="ts">
import { toast } from "vue3-toastify";


import Avatar from "~/components/general/Avatar/index.vue";
import FileButton from "~/components/general/FileButton/index.vue";
import Trash from "~/components/icons/Trash/index.vue";
import UploadCloud from "~/components/icons/UploadCloud/index.vue";

const props = defineProps({
  modelValue: {
    type: [Object as () => null | File, Array as () => File[]],
    default: null,
  },
  id: {
    type: String,
    default: "select-file",
  },
  label: {
    type: [String, Object as () => null],
    default: null,
  },
  subtitle: {
    type: String,
    default: null,
  },
  src: {
    type: String,
    default: null,
  },
  maxFileSize: {
    type: Number,
    default: 5,
  },
  validFileExtensions: {
    type: Array as () => string[],
    default: [],
  },
  isMultiple: {
    type: Boolean,
    default: false,
  },
  color: {
    type: String as () =>  'primary' | 'success' | 'info' | 'warning' |'error',
    default: 'primary'
  }
});

const fileInput = ref<HTMLInputElement | null>(null);
const isFileHovering = ref<boolean>(false);
const inActiveTimeout = ref<null | NodeJS.Timeout>(null);

const emit = defineEmits(["update:modelValue"]);

const fileProperties = computed(() => {
  const isImage = (ext: string) => {
    return ext === ".png" || ext === ".jpg" || ext === ".jpeg";
  };

  try {
    if (Array.isArray(props.modelValue)) {
      return props.modelValue.map((file) => ({
        name: file.name,
        size: ((file?.size ?? 0) / 1024 / 1024).toFixed(2),
        extension: `.${file.name.split(".").pop()}`,
        isImage: isImage(`.${file.name.split(".").pop()}`),
        url: URL.createObjectURL(file as Blob),
      }));
    } else {
      return {
        name: props.modelValue?.name ?? "",
        size: ((props.modelValue?.size ?? 0) / 1024 / 1024).toFixed(2),
        extension: `.${props.modelValue?.name.split(".").pop()}`,
        isImage: isImage(`.${props.modelValue?.name.split(".").pop()}`),
        url: URL.createObjectURL(props.modelValue as Blob),
      };
    }
  } catch (_) {
    return null;
  }
});

const isValidFile = (file: File) => {
  if (file.type && props.validFileExtensions.length > 0) {
    const fileExtension = `.${file.name.split(".").pop()}`;
    if (!props.validFileExtensions.find((vfe) => vfe === fileExtension)) {
      toast.error("Invalid file extension");
      return false;
    }
  }

  if (file.size > props.maxFileSize * 1024 * 1024) {
    toast.error(`File must be less than ${props.maxFileSize} MB`);
    return false;
  }

  return true;
};

function onDragging(isHovering: boolean) {
  isFileHovering.value = isHovering;

  if (isHovering) {
    if (inActiveTimeout.value !== null) {
      clearTimeout(inActiveTimeout.value);
    }
  } else {
    inActiveTimeout.value = setTimeout(() => {
      isFileHovering.value = isHovering;
    }, 50);
  }
}

function onChangeFile(event: any) {
  if (props.isMultiple) {
    const files: File[] = [...event.target?.files];
    if (files.every((file) => isValidFile(file)))
      emit("update:modelValue", [
        ...(props.modelValue as File[]).concat(...files),
      ]);
  } else {
    const file: File = event.target?.files[0];
    if (isValidFile(file)) emit("update:modelValue", file);
  }
}

function onDropFile(event: DragEvent) {
  isFileHovering.value = false;

  if (props.isMultiple) {
    const files: File[] = [...event.dataTransfer?.files!];

    if (files.length === 0) return;
    if (files.every((file) => isValidFile(file)))
      emit("update:modelValue", [
        ...(props.modelValue as File[]).concat(...files),
      ]);
  } else {
    const file = event.dataTransfer?.files[0];

    if (!file) return;
    if (isValidFile(file)) emit("update:modelValue", file);
  }
}


const dragDropColor = computed(() => {
  const variant = {
    primary: {
      hoverBg: 'hover:bg-primary-25',
      hoverBorder: 'hover:border-primary-200',
      activeBg: 'bg-primary-25',
      activeBorder: 'border-primary-200',
      iconBg1: 'bg-primary-50',
      iconBg2: 'bg-primary-100',
      iconStroke: 'stroke-primary-500',
      textColor: 'text-primary-500'
    },
    success: {
      hoverBg: 'hover:bg-success-25',
      hoverBorder: 'hover:border-success-200',
      activeBg: 'bg-success-25',
      activeBorder: 'border-success-200',
      iconBg1: 'bg-success-50',
      iconBg2: 'bg-success-100',
      iconStroke: 'stroke-success-500',
      textColor: 'text-success-500'
    },
    info: {
      hoverBg: 'hover:bg-info-25',
      hoverBorder: 'hover:border-info-200',
      activeBg: 'bg-info-25',
      activeBorder: 'border-info-200',
      iconBg1: 'bg-info-50',
      iconBg2: 'bg-info-100',
      iconStroke: 'stroke-info-500',
      textColor: 'text-info-500'
    },
    warning: {
      hoverBg: 'hover:bg-warning-25',
      hoverBorder: 'hover:border-warning-200',
      activeBg: 'bg-warning-25',
      activeBorder: 'border-warning-200',
      iconBg1: 'bg-warning-50',
      iconBg2: 'bg-warning-100',
      iconStroke: 'stroke-warning-500',
      textColor: 'text-warning-500'
    },
    error: {
      hoverBg: 'hover:bg-error-25',
      hoverBorder: 'hover:border-error-200',
      activeBg: 'bg-error-25',
      activeBorder: 'border-error-200',
      iconBg1: 'bg-error-50',
      iconBg2: 'bg-error-100',
      iconStroke: 'stroke-error-500',
      textColor: 'text-error-500'
    },
  };

  return variant[props.color];
});
</script>

<template>
  <div>
    <label
      v-if="props.label"
      :for="props.id"
      class="mb-1.5 text-sm font-semibold text-gray-700"
    >
      {{ props.label }}
    </label>

    <div v-if="props.isMultiple || !props.modelValue">
      <input
        :id="props.id"
        hidden
        ref="fileInput"
        type="file"
        :multiple="props.isMultiple"
        :accept="props.validFileExtensions.join(',')"
        @change="onChangeFile"
      />

      <div
        class="p-4 stroke-gray-700 border rounded-lg flex flex-col items-center justify-center transition-all space-y-3 cursor-pointer"
        :class="[
          isFileHovering 
            ? [dragDropColor.activeBg, dragDropColor.activeBorder] 
            : [dragDropColor.hoverBg, dragDropColor.hoverBorder]
        ]"
        @click="fileInput?.click()"
        @dragover.prevent="onDragging(true)"
        @dragleave.prevent="onDragging(false)"
        @drop.prevent="onDropFile"
      >
        <div class="p-2 aspect-square w-min rounded-full" :class="dragDropColor.iconBg1">
          <div class="p-2 aspect-square w-min rounded-full" :class="dragDropColor.iconBg2">
            <UploadCloud size="20" :class="dragDropColor.iconStroke" />
          </div>
        </div>

        <div class="space-y-1">
          <p v-if="!isFileHovering" class="text-sm text-gray-500 text-center">
            <span class="font-semibold" :class="dragDropColor.textColor">Click to upload</span>
            or drag and drop
          </p>
          <p v-else class="text-sm font-semibold" :class="dragDropColor.textColor">
            Release to drop file here
          </p>
          <p v-if="props.subtitle" class="text-sm text-gray-500 text-center">
            {{ props.subtitle }}
          </p>
        </div>
      </div>
    </div>

    <div>
      <div v-if="Array.isArray(fileProperties)" class="mt-4 space-y-2">
        <FileButton
          v-for="(file, i) in fileProperties"
          :title="file?.name"
          :subtitle="`${file?.size} MB`"
          :color="props.color"
          @on-click="
            emit('update:modelValue', [
              ...(props.modelValue as File[]).slice(0, i),
              ...(props.modelValue as File[]).slice(i + 1),
            ])
          "
        >
          <template v-if="file?.isImage" #prefix>
            <Avatar :src="file?.url" />
          </template>

          <template #suffix>
            <Trash size="20" :class="dragDropColor.iconStroke" />
          </template>
        </FileButton>
      </div>

      <FileButton
        v-else-if="fileProperties"
        :title="fileProperties?.name"
        :subtitle="`${fileProperties?.size} MB`"
        :color="props.color"
        @on-click="emit('update:modelValue', null)"
      >
        <template v-if="fileProperties?.isImage" #prefix>
          <Avatar :src="fileProperties?.url" />
        </template>

        <template #suffix>
          <Trash size="20" :class="dragDropColor.iconStroke" />
        </template>
      </FileButton>
    </div>
  </div>
</template>

<style scoped></style>
